-- Gjeneruar automatikisht. Importoni në bazën `sewpro`:
--   C:\xampp\mysql\bin\mysql.exe -u root sewpro < seed_grades.sql
-- I sigurt për ri-import (ON DUPLICATE KEY i përditëson).
--
-- RASTE KONTROLLI me rezultate të pritura të llogaritura me dorë:
--
-- 1) arber (57), Matematikë: mesataret mujore duhet të jenë
--    Shtator 5.00 (A), Tetor 4.50 (A), Nëntor 4.00 (B), Dhjetor 3.50 (B)
--    Janar 3.00 (C), Shkurt 2.50 (C), Mars 2.00 (D), Prill 1.50 (D),
--    Maj 1.00 (E), Qershor 5.00 (A)
--    Gjysmëvjetori I  = (5+4.5+4+3.5)/4      = 4.25 -> B (4.25)
--    Gjysmëvjetori II = (3+2.5+2+1.5+1+5)/6  = 2.50 -> C (2.50)
--    Nota vjetore     = (4.25+2.50)/2        = 3.38 -> C (3.38)
--
-- 2) dren (58), Matematikë: çdo notë A -> çdo mesatare 5.00 (A),
--    të dy gjysmëvjetorët A (5.00), vjetorja A (5.00)
--
-- 3) erald (59), Gjuhë Angleze: nota vetëm në Shtator e Tetor -
--    muajt e tjerë duhet të shfaqen bosh (—), gjysmëvjetori II 'Nuk ka notë',
--    vjetorja = vetëm gjysmëvjetori I
--
-- 4) Nota NË PRITJE me datën e sotme për klasën 3/1 (lëndët Matematikë
--    dhe Gjuhë Shqipe) - hyni si mësuesi 'Qemajl' për t'i aprovuar me
--    drag & drop; pastaj prindi i sheh në Raportin Ditor.
-- ============================================================

ON DUPLICATE KEY UPDATE grade = VALUES(grade), is_approved = VALUES(is_approved), approved_by = VALUES(approved_by), approved_at = VALUES(approved_at);

-- Notat në pritje për aprovim nga mësuesi (sot)
ON DUPLICATE KEY UPDATE grade = VALUES(grade), is_approved = VALUES(is_approved), approved_by = VALUES(approved_by), approved_at = VALUES(approved_at);
